#!/usr/bin/env -S npx ts-node -r tsconfig-paths/register

/**
 * File Upload/Download Example
 *
 * This example demonstrates how to use the advanced file upload/download capabilities
 * with multipart uploads, parallel transfers, and progress tracking.
 *
 * Prerequisites:
 * - A Unity Catalog volume (e.g., /Volumes/catalog/schema/volume)
 * - Valid Databricks authentication (see README.md)
 *
 * Usage:
 *   npx ts-node examples/files/upload-download.ts
 */

import {WorkspaceClient} from "@databricks/sdk-experimental";
import {readableToWeb} from "../../../src/fetch";
import * as fs from "fs";

async function main() {
    // Initialize the Databricks workspace client (uses default authentication)
    const client = new WorkspaceClient({});

    if (!process.env.DATABRICKS_VOLUME_PATH) {
        throw new Error("DATABRICKS_VOLUME_PATH is not set");
    }
    const volumePath = process.env.DATABRICKS_VOLUME_PATH.replace(
        /^\/Volumes\//,
        ""
    )
        .replace(/^\//, "")
        .replace(/\/$/, "");
    const remotePath = `/Volumes/${volumePath}/sdk-example-${Date.now()}.txt`;

    const path = __filename;
    const readable = readableToWeb(fs.createReadStream(path));

    console.log("Uploading file...");
    await client.files.upload({
        file_path: remotePath,
        contents: readable,
    });

    console.log("Downloading file...");
    const response = await client.files.download({file_path: remotePath});
    for await (const chunk of response.contents!) {
        console.log(new TextDecoder().decode(chunk));
    }

    console.log("Deleting file...");
    await client.files.delete({file_path: remotePath});
}

// Run the example
main().catch((error) => {
    console.error("Failed to run example:", error);
    process.exit(1);
});
